var e=[{id:`L5_1`,type:`dialog`,speaker:`LAIKA_CANARY_NULL_NULL`,text:{KOREA:`크윽……! 아아아악!!`,JPN:`くうっ……！　ああああ！！`,ENG:`Urgh...! AAAGH!!`,TWN:`唔呃……！啊啊啊啊！！`},stage:{bg:`BACKSTREET2`,slots:{L:null,C:{char_id:`LAIKA_CANARY_NULL_NULL`,face:`UNIT_HATE`},R:{char_id:`SWORD_ADMIN_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L6_1`,type:`dialog`,speaker:`SWORD_ADMIN_NULL_NULL`,text:{KOREA:`일부러 어깨를 내주고 내 팔을 잡은 건가?`,JPN:`わざと肩を犠牲にして私の腕を掴んだの？`,ENG:`You sacrificed your shoulder so you could grab my arm?`,TWN:`你是故意犧牲肩膀來抓住我的手臂嗎？`},stage:{bg:`BACKSTREET2`,slots:{L:null,C:{char_id:`LAIKA_CANARY_NULL_NULL`,face:`UNIT_HATE`},R:{char_id:`SWORD_ADMIN_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L7_1`,type:`dialog`,speaker:`SWORD_ADMIN_NULL_NULL`,text:{KOREA:`엄살 부리는 것 치곤 판단이 빨라. 단분자 커터에 대해 알고 있었나?`,JPN:`弱音を吐いてる割には判断が早いのね。単分子カッターについて知っていたの？`,ENG:`For such a crybaby, you are quick on your feet. Were you aware of the monomolecular blade?`,TWN:`你反應蠻快的，你是事先就想好要這麼做的？`},stage:{bg:`BACKSTREET2`,slots:{L:null,C:{char_id:`LAIKA_CANARY_NULL_NULL`,face:`UNIT_HATE`},R:{char_id:`SWORD_ADMIN_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L8_1`,type:`dialog`,speaker:`LAIKA_CANARY_NULL_NULL`,text:{KOREA:`그럼 다짜고짜 칼침 놓는데 송별회라도 열어 줄 거 같았냐?`,JPN:`じゃあ、いきなり剣を振りかざしてくる奴の送別会を開くとでも？`,ENG:`What? You thought I'd host a farewell party while you stabbed me?`,TWN:`你二話不說刀就揮過來，難道我就傻傻地坐以待斃嗎？`},stage:{bg:`BACKSTREET2`,slots:{L:null,C:{char_id:`LAIKA_CANARY_NULL_NULL`,face:`UNIT_SERIOUS`},R:{char_id:`SWORD_ADMIN_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L9_1`,type:`dialog`,speaker:`LAIKA_CANARY_NULL_NULL`,text:{KOREA:`바짓가랑이든 뭐든 붙잡고 있어야 도망 못 칠 거 아니야……!`,JPN:`ズボンの裾でもなんでも掴んでないと、逃げられるだろ……！`,ENG:`I need to grab onto something so you can't run away...!`,TWN:`不管是要抓衣角還是抓什麼都好，總之就是不能讓人逃掉……！`},stage:{bg:`BACKSTREET2`,slots:{L:null,C:{char_id:`LAIKA_CANARY_NULL_NULL`,face:`UNIT_IDLE`},R:{char_id:`SWORD_ADMIN_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L10_1`,type:`dialog`,speaker:`SWORD_ADMIN_NULL_NULL`,text:{KOREA:`도망쳐? 누가?`,JPN:`逃げる？　誰が？`,ENG:`Run? Who is running away?`,TWN:`逃掉？誰要逃？`},stage:{bg:`BACKSTREET2`,slots:{L:null,C:{char_id:`LAIKA_CANARY_NULL_NULL`,face:`UNIT_IDLE`},R:{char_id:`SWORD_ADMIN_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L11_1`,type:`dialog`,speaker:`LAIKA_CANARY_NULL_NULL`,text:{KOREA:`누구긴 누구야? 너지!`,JPN:`あんたに決まってるだろ！`,ENG:`Who do you think?! You!`,TWN:`什麼誰？當然是你囉！`},stage:{bg:`BACKSTREET2`,slots:{L:null,C:{char_id:`LAIKA_CANARY_NULL_NULL`,face:`UNIT_PRIDE`},R:{char_id:`SWORD_ADMIN_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L17_1`,type:`dialog`,speaker:`SWORD_ADMIN_NULL_NULL`,text:{KOREA:`큭!? 이건…… 페인트탄?`,JPN:`くっ！？　これは……ペイント弾？`,ENG:`Kgh?! This is... a paintball?`,TWN:`唔！？這是……漆彈？`},stage:{bg:`BACKSTREET2`,slots:{L:null,C:{char_id:`SWORD_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`FELICETTE_CANARY_NULL_NULL`,text:{KOREA:`라이카!!`,JPN:`ライカ！！`,ENG:`LAIKA!!`,TWN:`萊卡！！`},stage:{bg:`BACKSTREET2`,slots:{L:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L21_1`,type:`dialog`,speaker:`INTERN_FENRIR_NULL_NULL`,text:{KOREA:`비명 소리가 들려서 왔어요! 괜찮으세요!?`,JPN:`悲鳴が聞こえて来てみました！　大丈夫ですか！？`,ENG:`I heard you scream, so we came as fast as we could! Are you all right?!`,TWN:`我們聽到哀嚎聲趕緊跑來！你沒事吧！？`},stage:{bg:`BACKSTREET2`,slots:{L:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L25_1`,type:`dialog`,speaker:`SWORD_ADMIN_NULL_NULL`,text:{KOREA:`증원? 비명을 지른 게 이것 때문이었군.`,JPN:`応援？　悲鳴を上げたのはこれのためだったのね。`,ENG:`Backup? So that is why you were screaming.`,TWN:`增加人手？原來剛剛的慘叫聲用意是這樣。`},stage:{bg:`BACKSTREET2`,slots:{L:{char_id:`LAIKA_CANARY_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`SWORD_ADMIN_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L26_1`,type:`dialog`,speaker:`LAIKA_CANARY_NULL_NULL`,text:{KOREA:`헤헤…… 배짱 좋게 우리 앞마당에 쳐들어왔는데 당연한 거 아냐?`,JPN:`へへ……図々しく私たちの縄張りに入ってきたんだ、当たり前だろ？`,ENG:`Heh heh... You had the guts to ambush me in our territory, so why wouldn't I scream?`,TWN:`嘿嘿……你這麼大膽跑到人家地盤來撒野，這是起碼的待客之道吧？`},stage:{bg:`BACKSTREET2`,slots:{L:{char_id:`LAIKA_CANARY_NULL_NULL`,face:`UNIT_PRIDE`},C:null,R:{char_id:`SWORD_ADMIN_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L27_1`,type:`dialog`,speaker:`SWORD_ADMIN_NULL_NULL`,text:{KOREA:`……흥.`,JPN:`……フン。`,ENG:`...Hmph.`,TWN:`……哼`},stage:{bg:`BACKSTREET2`,slots:{L:{char_id:`LAIKA_CANARY_NULL_NULL`,face:`UNIT_PRIDE`},C:null,R:{char_id:`SWORD_ADMIN_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L31_1`,type:`dialog`,speaker:`LAIKA_CANARY_NULL_NULL`,text:{KOREA:`윽, 저게……! 거기 안 서……!`,JPN:`うっ、あいつ……！　待てよ……！`,ENG:`Ngh! Hey...! Stop right there...!`,TWN:`呃，給我……站住……！`},stage:{bg:`BACKSTREET2`,slots:{L:null,C:{char_id:`LAIKA_CANARY_NULL_NULL`,face:`UNIT_HATE`},R:null}}}];export{e as default};